import React from 'react';
import { Block, Theme } from '../../types';

interface TitleRendererProps {
  block: Block;
  theme: Theme;
}

export function TitleRenderer({ block, theme }: TitleRendererProps) {
  const text = Array.isArray(block.content) ? block.content.join(' ') : (block.content || '') as string;
  const highlight = block.options?.highlight;
  const size = block.options?.size || 'md';
  const variant = block.options?.variant;
  const hasBgHighlight = text.includes('[[');
  const fontVariant = block.options?.fontVariant || 'padrão';

  const sizeClasses = {
    sm: `text-[64px] font-black tracking-tight ${hasBgHighlight ? 'leading-[1.2]' : 'leading-[1.1]'}`,
    md: `${theme.typography.title} ${hasBgHighlight ? 'leading-[1.15]' : 'leading-[0.95]'}`,
    lg: `text-[180px] font-[1000] tracking-[-0.08em] ${hasBgHighlight ? 'leading-[1.0]' : 'leading-[0.85]'}`
  };

  // Se fontVariant for destaque, usa a secundária. Senão, usa a primária (padrão).
  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  const style: React.CSSProperties = { 
    color: block.options?.color || theme.colors.textPrimary,
    textWrap: 'balance' as any,
    fontSize: block.options?.fontSize ? `${block.options.fontSize}px` : undefined,
    letterSpacing: block.options?.letterSpacing !== undefined ? `${block.options.letterSpacing}px` : undefined,
    lineHeight: block.options?.lineHeight !== undefined ? block.options.lineHeight : undefined,
    textAlign: block.options?.textAlign || (block.options?.align as any) || 'left',
    fontFamily: selectedFont,
    // Ajuste de peso para fontes serifadas comuns de destaque
    fontWeight: (selectedFont.includes('Serif') || selectedFont.includes('Playfair')) ? 400 : undefined,
  };

  const renderRichText = (input: string) => {
    let parts: (string | React.ReactNode)[] = [input];

    // Handle Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline px-6 py-1 rounded-2xl mx-1 font-black"
                  style={{ 
                    backgroundColor: theme.colors.hlBgColor || theme.colors.accent,
                    color: theme.colors.hlTextColor || '#000',
                    WebkitBoxDecorationBreak: 'clone',
                    boxDecorationBreak: 'clone' as any,
                    fontFamily: theme.typography.fontFamily // Destaques de fundo usam a padrão para legibilidade
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Highlight (options.highlight)
    if (highlight && typeof highlight === 'string' && highlight.trim() !== '') {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(new RegExp(`(${highlight})`, 'gi'));
          split.forEach((s, i) => {
            if (s.toLowerCase() === highlight.toLowerCase()) {
              newParts.push(<span key={`hl-${i}`} style={{ color: theme.colors.highlight }}>{s}</span>);
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Markdown Bold **
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) {
            finalParts.push(<span key={`bold-${i}`} className="font-black">{s}</span>);
          } else if (s !== "") {
            finalParts.push(s);
          }
        });
      } else {
        finalParts.push(part);
      }
    });

    return finalParts;
  };

  if (variant === 'oval') {
     return (
        <div className="relative inline-flex items-center justify-center py-10 px-20 mb-6">
           <div className="absolute inset-0 border-[10px] rounded-[100%] border-white opacity-20 transform scale-[1.3] scale-y-[0.8]" />
           <h1 
              className={`${sizeClasses[size as keyof typeof sizeClasses]} uppercase relative z-10 italic`} 
              style={{ ...style, textAlign: 'center' }}
              data-block-type="TITLE"
            >
              {renderRichText(text)}
            </h1>
        </div>
     );
  }

  return (
    <h1 
      className={`${sizeClasses[size as keyof typeof sizeClasses]}`} 
      style={style}
      data-block-type="TITLE"
    >
      {renderRichText(text)}
    </h1>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';

interface ListRendererProps {
  block: Block;
  theme: Theme;
}

export function ListRenderer({ block, theme }: ListRendererProps) {
  const items = Array.isArray(block.content) ? block.content : [block.content];
  const isBox = block.options?.variant === 'box';
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  const commonStyle: React.CSSProperties = {
    fontFamily: selectedFont,
    fontSize: block.options?.fontSize ? `${block.options.fontSize}px` : undefined,
    letterSpacing: block.options?.letterSpacing !== undefined ? `${block.options.letterSpacing}px` : undefined,
    lineHeight: block.options?.lineHeight !== undefined ? block.options.lineHeight : undefined,
    textAlign: block.options?.textAlign || (block.options?.align as any) || 'left',
    color: block.options?.color || undefined
  };

  const renderRichText = (text: string, highlight?: string) => {
    let parts: (string | React.ReactNode)[] = [text];

    // Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline-block px-2 py-0.5 rounded-md mx-1 align-baseline font-black"
                  style={{ 
                    backgroundColor: theme.colors.hlBgColor || theme.colors.accent,
                    color: theme.colors.hlTextColor || '#000',
                    fontFamily: theme.typography.fontFamily
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Highlight logic (options.highlight)
    if (highlight) {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(new RegExp(`(${highlight})`, 'gi'));
          split.forEach((s, i) => {
            if (s.toLowerCase() === highlight.toLowerCase()) {
              newParts.push(
                <span 
                  key={`hl-${i}`} 
                  className="font-black" 
                  style={{ fontWeight: 900, color: theme.colors.highlight }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Markdown Bold logic
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) {
            finalParts.push(
              <span 
                key={`bold-${i}`} 
                className="font-black" 
                style={{ fontWeight: 900, color: block.options?.color || theme.colors.textPrimary }}
              >
                {s}
              </span>
            );
          } else if (s !== "") {
            finalParts.push(s);
          }
        });
      } else {
        finalParts.push(part);
      }
    });

    return finalParts;
  };

  return (
    <div 
      className={`flex flex-col ${isBox ? 'gap-3 w-full' : 'gap-4 mt-2 w-full'}`}
      style={{ textAlign: commonStyle.textAlign }}
      data-block-type="LIST"
    >
      {items.map((item, index) => {
        const text = item as string;
        const highlight = block.options?.highlight;
        const content = renderRichText(text, highlight);

        if (isBox) {
          return (
            <div 
              key={index} 
              className="w-full py-4 px-10 rounded-md text-[34px]" 
              style={{ 
                ...commonStyle,
                backgroundColor: theme.colors.highlight, 
                color: '#000', 
                fontWeight: 900,
                textAlign: 'center' 
              }}
            >
              {content}
            </div>
          );
        }

        return (
          <div key={index} className={`flex items-start gap-6 ${commonStyle.textAlign === 'center' ? 'justify-center' : (commonStyle.textAlign === 'right' ? 'justify-end' : 'justify-start')}`}>
            {commonStyle.textAlign !== 'right' && (
              <div 
                className="mt-[22px] w-3 h-3 rounded-full shrink-0" 
                style={{ 
                  backgroundColor: theme.colors.accent,
                  boxShadow: `0 0 10px ${theme.colors.accent}80` 
                }} 
              />
            )}
            <p 
              className={theme.typography.body} 
              style={{ 
                ...commonStyle, 
                color: commonStyle.color || theme.colors.textSecondary, 
                fontWeight: 300 
              }}
            >
              {content}
            </p>
            {commonStyle.textAlign === 'right' && (
              <div 
                className="mt-[22px] w-3 h-3 rounded-full shrink-0" 
                style={{ 
                  backgroundColor: theme.colors.accent,
                  boxShadow: `0 0 10px ${theme.colors.accent}80` 
                }} 
              />
            )}
          </div>
        );
      })}
    </div>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface BoxRendererProps {
  block: Block;
  theme: Theme;
  isGridMember?: boolean;
  indexInGrid?: number;
  onEditIcon?: (block: Block) => void;
}

export function BoxRenderer({ block, theme, isGridMember, indexInGrid = 0, onEditIcon }: BoxRendererProps) {
  const text = (block.content || '') as string;
  const iconName = block.options?.icon;
  const customIcon = block.options?.customIcon;
  const variant = block.options?.variant || 'default';
  const align = block.options?.align || (isGridMember ? 'center' : 'left');
  const hasBgHighlight = text.includes('[[');
  const customPadding = block.options?.padding;
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  const renderRichText = (input: string) => {
    let parts: (string | React.ReactNode)[] = [input];
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(<span key={`bg-hl-${i}`} className="inline px-4 py-1 rounded-xl mx-1 font-black" style={{ backgroundColor: theme.colors.hlBgColor || '#fff', color: theme.colors.hlTextColor || '#000', WebkitBoxDecorationBreak: 'clone', boxDecorationBreak: 'clone' as any, fontFamily: theme.typography.fontFamily }}>{s}</span>);
            } else if (s !== "") { newParts.push(s); }
          });
        } else { newParts.push(part); }
      });
      parts = newParts;
    }
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) { finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>); }
          else if (s !== "") { finalParts.push(s); }
        });
      } else { finalParts.push(part); }
    });
    return finalParts;
  };

  const isOutlined = variant === 'outlined';
  const isPill = variant === 'pill';
  const shouldReverseIcon = !isGridMember && indexInGrid % 2 === 1;
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;

  const bgColor = isOutlined ? 'transparent' : (block.options?.color ? `${block.options.color}20` : (theme.colors.cardBg || theme.colors.accent));
  const textColor = block.options?.color || theme.colors.cardTextColor || (isOutlined ? theme.colors.textPrimary : '#000000');

  const renderIcon = () => {
    const size = isGridMember ? 80 : (isPill ? 50 : 120);
    const renderSize = block.options?.fontSize ? block.options.fontSize * 1.5 : size;

    if (customIcon) {
       if (customIcon.startsWith('<svg')) return (<div style={{ width: renderSize, height: renderSize }} className="flex items-center justify-center" dangerouslySetInnerHTML={{ __html: customIcon }} />);
       if (customIcon.startsWith('http') || customIcon.startsWith('data:image')) return <img src={customIcon} style={{ width: renderSize, height: renderSize }} className="object-contain rounded-xl" alt="icon" />;
       const IconFromCustom = (Icons as any)[customIcon];
       if (IconFromCustom) return <IconFromCustom size={renderSize} strokeWidth={1.5} />;
    }
    if (iconName) {
      const IconComponent = (Icons as any)[iconName];
      if (IconComponent) return <IconComponent size={renderSize} strokeWidth={1.5} />;
    }
    return null;
  };

  if (isPill) {
     return (
        <div className="relative w-full p-12 rounded-[100px] flex items-center transition-all overflow-hidden border border-white/5 shadow-2xl" style={{ backgroundColor: block.options?.color || '#FFFFFF', color: '#000000', textAlign: 'left', fontFamily: selectedFont }}>
           <div className="flex-1">
              <h4 className="text-[38px] font-black leading-tight tracking-tight mb-2">{renderRichText(text)}</h4>
              <p className="text-[24px] opacity-60 font-medium">Informação adicional aqui...</p>
           </div>
           <div className="w-16 h-16 rounded-full border-2 border-black/10 flex items-center justify-center shrink-0">
              <Icons.ArrowUpRight size={32} strokeWidth={2.5} />
           </div>
        </div>
     );
  }

  const paddingValue = customPadding !== undefined ? `${customPadding}px` : '48px';
  const fontSize = block.options?.fontSize ? `${block.options.fontSize}px` : '34px';

  return (
    <div 
      className={`relative rounded-[60px] flex flex-col transition-all overflow-hidden justify-center ${isOutlined ? 'border-[4px]' : ''} ${isGridMember ? 'w-full h-full' : 'w-fit'}`} 
      style={{ 
        padding: paddingValue,
        backgroundColor: bgColor, 
        opacity: isOutlined ? 1 : opacity, 
        borderColor: theme.colors.accent, 
        color: textColor, 
        textAlign: align === 'center' ? 'center' : 'left',
        fontFamily: selectedFont
      }}
    >
      <div className={`flex items-center gap-6 ${align === 'center' ? 'flex-col' : (shouldReverseIcon ? 'flex-row-reverse' : 'flex-row')}`}>
        <div onClick={() => onEditIcon?.(block)} className="group relative cursor-pointer shrink-0">
          <div className="opacity-100 group-hover:opacity-70 transition-opacity">{renderIcon()}</div>
          <div className="absolute inset-[-15px] bg-brand/20 border-2 border-brand rounded-3xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
             <Icons.Edit3 size={32} className="text-brand" />
          </div>
        </div>
        <div 
          className={`${hasBgHighlight ? '!leading-[1.5]' : '!leading-[1.2]'} tracking-tight font-black uppercase ${align === 'center' ? 'mt-4' : ''}`}
          style={{ fontSize }}
        >
          {renderRichText(text)}
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface CardRendererProps {
  block: Block;
  theme: Theme;
  onEditIcon?: (block: Block) => void;
}

export function CardRenderer({ block, theme, onEditIcon }: CardRendererProps) {
  const customIcon = block.options?.customIcon;
  const iconName = block.options?.icon;
  const text = Array.isArray(block.content) ? block.content.join(' ') : (block.content || '') as string;
  const highlight = block.options?.highlight;
  const variant = block.options?.variant || 'default';
  const hasBgHighlight = text.includes('[[');
  const isAccent = variant === 'accent' || variant === 'box' || variant === 'default';
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;
  const cardColor = theme.colors.cardBg || theme.colors.accent;
  const textColor = theme.colors.cardTextColor || (isAccent ? '#000000' : theme.colors.textPrimary);
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  const containerStyles: React.CSSProperties = {
    backgroundColor: isAccent ? cardColor : 'rgba(255,255,255,0.06)',
    opacity: isAccent ? opacity : 1,
    borderColor: isAccent ? 'transparent' : 'rgba(255,255,255,0.1)',
    borderWidth: '2px',
    color: textColor,
    borderRadius: '40px',
    textWrap: 'balance' as any,
    fontFamily: selectedFont
  };

  const renderRichContent = () => {
    let parts: (string | React.ReactNode)[] = [text];
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(<span key={`bg-hl-${i}`} className="inline px-3 py-1 rounded-lg mx-1 font-black" style={{ backgroundColor: theme.colors.hlBgColor || (isAccent ? '#fff' : theme.colors.accent), color: theme.colors.hlTextColor || '#000', WebkitBoxDecorationBreak: 'clone', boxDecorationBreak: 'clone' as any, fontFamily: theme.typography.fontFamily }}>{s}</span>);
            } else if (s !== "") { newParts.push(s); }
          });
        } else { newParts.push(part); }
      });
      parts = newParts;
    }
    if (highlight && typeof highlight === 'string' && highlight.trim() !== '') {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(new RegExp(`(${highlight})`, 'gi'));
          split.forEach((s, i) => {
            if (s.toLowerCase() === highlight.toLowerCase()) {
              newParts.push(<span key={`hl-${i}`} className="font-black" style={{ color: isAccent ? '#000' : theme.colors.highlight, fontWeight: 900 }}>{s}</span>);
            } else if (s !== "") { newParts.push(s); }
          });
        } else { newParts.push(part); }
      });
      parts = newParts;
    }
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) { finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>); }
          else if (s !== "") { finalParts.push(s); }
        });
      } else { finalParts.push(part); }
    });
    return finalParts;
  };

  const renderIcon = () => {
    if (customIcon) {
       if (customIcon.startsWith('<svg')) return (<div className="w-12 h-12 flex items-center justify-center" dangerouslySetInnerHTML={{ __html: customIcon }} style={{ color: isAccent ? textColor : theme.colors.accent }} />);
       if (customIcon.startsWith('http') || customIcon.startsWith('data:image')) return <img src={customIcon} className="w-12 h-12 object-contain rounded-md" alt="icon" />;
       const IconFromCustom = (Icons as any)[customIcon];
       if (IconFromCustom) return <IconFromCustom size={48} strokeWidth={2} />;
    }
    const targetIconName = iconName || (variant === 'accent' || variant === 'default' ? 'Zap' : 'CircleDot');
    const IconComponent = (Icons as any)[targetIconName];
    if (IconComponent) return <IconComponent size={48} strokeWidth={2} />;
    return null;
  };

  return (
    <div className="relative flex items-center gap-8 p-10 w-full transition-all shadow-lg hover:translate-y-[-4px]" style={containerStyles}>
      <div onClick={() => onEditIcon?.(block)} className="group relative cursor-pointer shrink-0">
        <div className="opacity-80 group-hover:opacity-100 transition-opacity" style={{ color: isAccent ? textColor : theme.colors.accent }}>{renderIcon()}</div>
        <div className="absolute inset-[-10px] bg-brand/20 border-2 border-brand rounded-xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
           <Icons.Edit3 size={20} className="text-brand" />
        </div>
      </div>
      <div className={`flex-1 text-[32px] ${hasBgHighlight ? '!leading-[1.7]' : '!leading-[1.3]'} tracking-tight`} style={{ fontWeight: 300 }}>{renderRichContent()}</div>
    </div>
  );
}

