};

import React from 'react';
import { Block, Theme } from '../../types';

export function BadgeRenderer({ block, theme }: { block: Block; theme: Theme }) {
  const text = block.content as string;
  const highlight = block.options?.highlight;
  const hasBgHighlight = text.includes('[[');
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  // Cor de texto personalizada ou fallback
  const textColor = theme.colors.cardTextColor || '#000000';

  const renderContent = () => {
    let parts: (string | React.ReactNode)[] = [text];

    // Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline px-3 py-1 rounded-md mx-1 font-black"
                  style={{ 
                    backgroundColor: theme.colors.hlBgColor || '#fff',
                    color: theme.colors.hlTextColor || '#000',
                    WebkitBoxDecorationBreak: 'clone',
                    boxDecorationBreak: 'clone' as any,
                    fontFamily: theme.typography.fontFamily // Destaques de fundo usam a fonte principal para legibilidade
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Highlight (options.highlight)
    {
      const highlightTerm = highlight;
      if (highlightTerm) {
        const newParts: (string | React.ReactNode)[] = [];
        parts.forEach(part => {
          if (typeof part === 'string') {
            const split = part.split(new RegExp(`(${highlightTerm})`, 'gi'));
            split.forEach((s, i) => {
              if (s.toLowerCase() === highlightTerm.toLowerCase()) {
                newParts.push(<span key={i} className="font-black">{s}</span>);
              } else if (s !== "") {
                newParts.push(s);
              }
            });
          } else {
            newParts.push(part);
          }
        });
        parts = newParts;
      }
    }

    return parts;
  };

  return (
    <div 
      className={`inline-block px-10 py-6 text-[28px] font-normal rounded-lg ${hasBgHighlight ? '!leading-[1.8]' : '!leading-[1.3]'}`}
      style={{ 
        backgroundColor: theme.colors.cardBg || theme.colors.highlight, 
        opacity: opacity,
        color: textColor,
        textWrap: 'balance' as any,
        maxWidth: '100%',
        fontFamily: selectedFont
      }}
    >
      {renderContent()}
    </div>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';

export function UserRenderer({ block, theme }: { block: Block; theme: Theme }) {
  const name = block.content as string;
  const handle = block.options?.handle || '@handle';
  const avatar = block.options?.avatar || 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&q=80&w=200';
  const hideName = block.options?.hideName;
  const isLarge = block.options?.size === 'lg';
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  return (
    <div className={`flex items-center gap-6 mb-10 transition-all ${isLarge ? 'gap-8' : 'gap-4'}`}>
      <div 
        className={`rounded-full overflow-hidden border-2 border-white/10 shrink-0 shadow-xl transition-all ${isLarge ? 'w-32 h-32' : 'w-16 h-16'}`}
      >
        <img src={avatar} alt={name} className="w-full h-full object-cover" />
      </div>
      <div className="flex flex-col justify-center">
        {!hideName && (
          <span 
            className={`${isLarge ? 'text-[32px]' : 'text-[20px]'} font-black leading-none text-white tracking-tight mb-1`}
            style={{ fontFamily: selectedFont }}
          >
            {name}
          </span>
        )}
        <span 
          className={`${isLarge ? 'text-[24px]' : 'text-[14px]'} font-bold opacity-70 text-brand tracking-tight`}
          style={{ fontFamily: theme.typography.fontFamily }}
        >
          {handle}
        </span>
      </div>
    </div>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';

interface FooterRendererProps {
  block: Block;
  theme: Theme;
}

export function FooterRenderer({ block, theme }: FooterRendererProps) {
  const fontVariant = block.options?.fontVariant || 'padrão';

  const selectedFont = fontVariant === 'destaque' 
    ? (theme.typography.fontFamilySecondary || '"Instrument Serif", serif') 
    : theme.typography.fontFamily;

  return (
    <footer
      className={theme.typography.small}
      style={{ 
        color: theme.colors.muted,
        fontFamily: selectedFont 
      }}
    >
      {block.content as string}
    </footer>
  );
}
